preRunWindow.query:
#graphql
query BulkOperationsBaseOverlayPreRun($first: Int!, $sortKey: BulkOperationsSortKeys, $reverse: Boolean) {
  bulkOperations(first: $first, sortKey: $sortKey, reverse: $reverse) {
    nodes {

  id
  status
  type
  errorCode
  createdAt
  completedAt
  objectCount
  rootObjectCount
  fileSize
  url
  partialDataUrl
  query

    }
    pageInfo {
      hasNextPage
      hasPreviousPage
      startCursor
      endCursor
    }
  }
}

run.query:
#graphql
mutation BulkOperationRunQueryBaseOverlay($query: String!) {
  bulkOperationRunQuery(query: $query) {
    bulkOperation {

  id
  status
  type
  errorCode
  createdAt
  completedAt
  objectCount
  rootObjectCount
  fileSize
  url
  partialDataUrl
  query

    }
    userErrors {
      field
      message
    }
  }
}

